// schema-extractor walks the Globular Go tree, parses
// `+globular:schema:` pragma blocks, and emits two artifacts:
//
//  1. A JSON index at `golang/schema_reference/schema.json`, embedded
//     at build time into the MCP server + CLI.
//  2. A human-readable reference at `docs/schema.md`.
//
// Running the tool is idempotent: the same Go tree always produces the
// same bytes. CI should diff the generated artifacts against HEAD and
// fail the build when pragmas changed without the generated files
// being committed — see docs/architecture/cluster-introspection-plan.md
// Phase 4a for the enforcement plan.
//
// Usage:
//
//	go run ./tools/schema-extractor \
//	    -root ./ \
//	    -json ./schema_reference/schema.json \
//	    -md   ../docs/schema.md
//
// (Paths above assume the command is run from `golang/`. All paths are
// resolved relative to the working directory.)
package main

import (
	"encoding/json"
	"flag"
	"fmt"
	"os"
	"strings"
	"time"

	"github.com/globulario/services/golang/schema_reference"
)

func main() {
	var (
		root    = flag.String("root", ".", "root directory to scan for .go files")
		jsonOut = flag.String("json", "schema_reference/schema.json", "output path for the JSON index (embedded into binaries)")
		mdOut   = flag.String("md", "../docs/schema.md", "output path for the human-readable markdown reference")
		strict  = flag.Bool("strict", true, "fail on orphan pragmas / missing required fields")
	)
	flag.Parse()

	res, errs := schema_reference.ExtractTree(*root)
	res.GeneratedAtUnix = time.Now().Unix()

	if *strict && len(errs) > 0 {
		for _, e := range errs {
			fmt.Fprintln(os.Stderr, "schema-extractor:", e)
		}
		fmt.Fprintln(os.Stderr, "schema-extractor: aborting due to errors (pass -strict=false to ignore)")
		os.Exit(1)
	}

	// JSON is written with stable indentation so diffs read cleanly
	// when a pragma changes.
	j, err := json.MarshalIndent(res, "", "  ")
	if err != nil {
		fmt.Fprintln(os.Stderr, "schema-extractor: marshal:", err)
		os.Exit(1)
	}
	j = append(j, '\n')
	if err := os.WriteFile(*jsonOut, j, 0o644); err != nil {
		fmt.Fprintln(os.Stderr, "schema-extractor: write json:", err)
		os.Exit(1)
	}

	md := renderMarkdown(res)
	if err := os.WriteFile(*mdOut, []byte(md), 0o644); err != nil {
		fmt.Fprintln(os.Stderr, "schema-extractor: write md:", err)
		os.Exit(1)
	}

	fmt.Fprintf(os.Stderr, "schema-extractor: wrote %d entries → %s, %s\n", len(res.Entries), *jsonOut, *mdOut)
}

// renderMarkdown emits a human-readable schema reference. One section
// per entry, sorted by KeyPattern (already sorted by the extractor),
// with a short table-of-contents at the top.
func renderMarkdown(res schema_reference.ExtractResult) string {
	var b strings.Builder
	b.WriteString("# Globular Key Schema Reference\n\n")
	b.WriteString("_Generated by `golang/tools/schema-extractor`._ Do not edit by hand — update the `+globular:schema:` pragmas on the Go types and re-run the extractor.\n\n")
	b.WriteString(fmt.Sprintf("**Entries:** %d\n\n", len(res.Entries)))
	b.WriteString("## Contents\n\n")
	for _, e := range res.Entries {
		b.WriteString(fmt.Sprintf("- [`%s`](#%s)\n", e.KeyPattern, slug(e.KeyPattern)))
	}
	b.WriteString("\n---\n\n")
	for _, e := range res.Entries {
		b.WriteString(fmt.Sprintf("### `%s` <a id=\"%s\"></a>\n\n", e.KeyPattern, slug(e.KeyPattern)))
		if e.Description != "" {
			b.WriteString(e.Description + "\n\n")
		}
		b.WriteString(fmt.Sprintf("- **Go type:** `%s`\n", e.TypeName))
		b.WriteString(fmt.Sprintf("- **Writer:** `%s`\n", e.Writer))
		if len(e.Readers) > 0 {
			b.WriteString(fmt.Sprintf("- **Readers:** `%s`\n", strings.Join(e.Readers, "`, `")))
		}
		if e.Invariants != "" {
			b.WriteString(fmt.Sprintf("- **Invariants:** %s\n", e.Invariants))
		}
		if e.SinceVersion != "" {
			b.WriteString(fmt.Sprintf("- **Since:** %s\n", e.SinceVersion))
		}
		if e.SourceFile != "" {
			b.WriteString(fmt.Sprintf("- **Source:** `%s:%d`\n", e.SourceFile, e.SourceLine))
		}
		b.WriteString("\n")
	}
	return b.String()
}

// slug turns a key pattern into a markdown anchor. Kept minimal: lower
// case, replace non-alnum with `-`, collapse runs.
func slug(s string) string {
	var b strings.Builder
	b.Grow(len(s))
	lastDash := false
	for _, r := range strings.ToLower(s) {
		switch {
		case r >= 'a' && r <= 'z', r >= '0' && r <= '9':
			b.WriteRune(r)
			lastDash = false
		default:
			if !lastDash {
				b.WriteByte('-')
				lastDash = true
			}
		}
	}
	return strings.Trim(b.String(), "-")
}
